CREATE TYPE notification_type AS ENUM (
  'user_registration',
  'suspicious_activity',
  'system_error',
  'verification_request',
  'verification_approved',
  'verification_rejected',
  'transaction_initiated',
  'transaction_completed',
  'document_uploaded',
  'role_changed',
  'user_suspended'
);

CREATE TYPE notification_priority AS ENUM ('low', 'medium', 'high', 'critical');

CREATE TABLE IF NOT EXISTS admin_notifications (
  id SERIAL PRIMARY KEY,
  recipient_id INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  type notification_type NOT NULL,
  priority notification_priority DEFAULT 'medium' NOT NULL,
  title TEXT NOT NULL,
  message TEXT NOT NULL,
  metadata JSONB,
  read BOOLEAN DEFAULT false NOT NULL,
  read_at TIMESTAMP,
  created_at TIMESTAMP DEFAULT NOW() NOT NULL
);

CREATE INDEX admin_notifications_recipient_idx ON admin_notifications(recipient_id);
CREATE INDEX admin_notifications_type_idx ON admin_notifications(type);
CREATE INDEX admin_notifications_read_idx ON admin_notifications(read);
CREATE INDEX admin_notifications_created_at_idx ON admin_notifications(created_at);
